let{test,expect}=require("@playwright/test"),config={languages:[{code:"en",name:"English",dir:"ltr",default:!0},{code:"es",name:"Español",dir:"ltr"},{code:"fr",name:"Français",dir:"ltr"},{code:"ar",name:"العربية",dir:"rtl"}],baseUrl:"http://localhost:8001"};test("Content should change when clicking the Spanish debug button",async({page:t})=>{await t.goto(config.baseUrl),await t.waitForSelector(".signup-button");var e=await t.textContent(".signup-button"),a=(console.log("English Sign Up text:",e),await t.screenshot({path:"test-results/main-website-english.png"}),await t.click('button:has-text("Go to Spanish Version")'),await t.waitForURL("**/es/**"),await t.waitForSelector(".signup-button"),await t.waitForTimeout(1e3),await t.screenshot({path:"test-results/main-website-spanish.png"}),await t.textContent(".signup-button")),e=(console.log("Spanish Sign Up text:",a),expect(a).not.toBe(e),expect(a).toBe("Registrarse"),await t.evaluate(()=>document.documentElement.lang));expect(e).toBe("es")}),test("Content should change when using the language switcher",async({page:t})=>{await t.goto(config.baseUrl),await t.waitForSelector(".signup-button");var e=await t.textContent(".signup-button"),a=(console.log("English Sign Up text:",e),await t.click('button:has-text("Toggle Language Dropdown")'),await t.waitForSelector(".language-switcher-dropdown:visible"),await t.screenshot({path:"test-results/main-website-language-switcher-open.png"}),await t.click('.language-option[data-lang="es"]'),await t.waitForURL("**/es/**"),await t.waitForSelector(".signup-button"),await t.waitForTimeout(1e3),await t.textContent(".signup-button")),e=(console.log("Spanish Sign Up text:",a),expect(a).not.toBe(e),expect(a).toBe("Registrarse"),await t.evaluate(()=>document.documentElement.lang));expect(e).toBe("es")});